def _iceberg_column_to_nested(iceberg_column: IcebergColumn) -> IcebergColumnNested:
    """Convert flat IcebergColumn to nested format."""
    attrs = IcebergColumnAttributes()
    _populate_iceberg_column_attrs(attrs, iceberg_column)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        iceberg_column, _ICEBERG_COLUMN_REL_FIELDS, IcebergColumnRelationshipAttributes
    )
    return IcebergColumnNested(
        guid=iceberg_column.guid,
        type_name=iceberg_column.type_name,
        status=iceberg_column.status,
        version=iceberg_column.version,
        create_time=iceberg_column.create_time,
        update_time=iceberg_column.update_time,
        created_by=iceberg_column.created_by,
        updated_by=iceberg_column.updated_by,
        classifications=iceberg_column.classifications,
        classification_names=iceberg_column.classification_names,
        meanings=iceberg_column.meanings,
        labels=iceberg_column.labels,
        business_attributes=iceberg_column.business_attributes,
        custom_attributes=iceberg_column.custom_attributes,
        pending_tasks=iceberg_column.pending_tasks,
        proxy=iceberg_column.proxy,
        is_incomplete=iceberg_column.is_incomplete,
        provenance_type=iceberg_column.provenance_type,
        home_id=iceberg_column.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _iceberg_column_from_nested(nested: IcebergColumnNested) -> IcebergColumn:
    """Convert nested format to flat IcebergColumn."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else IcebergColumnAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _ICEBERG_COLUMN_REL_FIELDS,
        IcebergColumnRelationshipAttributes,
    )
    return IcebergColumn(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_iceberg_column_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _iceberg_column_to_nested_bytes(
    iceberg_column: IcebergColumn, serde: Serde
) -> bytes:
    """Convert flat IcebergColumn to nested JSON bytes."""
    return serde.encode(_iceberg_column_to_nested(iceberg_column))


def _iceberg_column_from_nested_bytes(data: bytes, serde: Serde) -> IcebergColumn:
    """Convert nested JSON bytes to flat IcebergColumn."""
    nested = serde.decode(data, IcebergColumnNested)
    return _iceberg_column_from_nested(nested)


